class Solution {
public:
    string solveEquation(string equation) {
        int x = 0, num = 0;
        for (int i = 0; i < equation.size(); i++) {
            if (equation[i] == 'x') {
                if (i > 0 && equation[i - 1] == '-') {
                    x--;
                } else {
                    x++;
                }
            } else if (isdigit(equation[i])) {
                int j = i + 1;
                while (j < equation.size() && isdigit(equation[j])) {
                    j++;
                }
                num = stoi(equation.substr(i, j - i));
                if (equation[i] == '-') {
                    num *= -1;
                }
                if (equation[i] == 'x') {
                    x += num;
                } else {
                    if (equation[i] == '+') {
                        x += num;
                    } else {
                        x -= num;
                    }
                }
            }
        }
        if (x == 0) {
            return "No solution";
        } else if (x == 1) {
            return "x=0";
        } else {
            return "x=" + to_string(0);
        }
    }
};
